// LESSON: Reference Page 1 - Undantag.
// You will learn: Throw, catch, and wrap errors at validation and I/O boundaries.
class Prog2Reference433 {
  // EXEMPEL 1: throw skapar ett undantag nar ett kontrakt bryts.
  static void setAge(int age) {
    if (age < 0) { throw new IllegalArgumentException("age"); }
  }
  // EXEMPEL 2: try/catch fangar ett vantat fel vid en grans.
  static int parseOrZero(String text) {
    try { return Integer.parseInt(text); }
    catch (NumberFormatException error) { return 0; }
  }
  // EXEMPEL 3: try-with-resources stanger resurser automatiskt.
  static String readFirstLine(String text) throws java.io.IOException {
    try (java.io.BufferedReader reader = new java.io.BufferedReader(new java.io.StringReader(text))) {
      return reader.readLine();
    }
  }
}
